Le debounce permet d'attendre que l'utilisateur ait fini de taper avant d'envoyer la requête API. Il évite d'effectuer un appel à chaque frappe (ce qui surcharge le serveur et l'interface).

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), delay);
  };
}

// Utilisation avec React
const debouncedSearch = useCallback(
  debounce((query) => {
    if (query.length >= 2) fetchSuggestions(query);
  }, 300),
  []
);
```

```jsx
import { useState, useEffect, useRef, useCallback } from 'react';
import { debounce } from 'lodash'; // ou votre propre implémentation

const SearchBar = () => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const inputRef = useRef(null);

  const fetchSuggestions = useCallback(async (searchTerm) => {
    if (searchTerm.length < 2) {
      setSuggestions([]);
      return;
    }
    setLoading(true);
    try {
      const response = await fetch(`/api/products/search?q=${encodeURIComponent(searchTerm)}`);
      const data = await response.json();
      setSuggestions(data);
    } catch (error) {
      console.error('Erreur recherche:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  const debouncedFetch = useCallback(debounce(fetchSuggestions, 300), [fetchSuggestions]);

  const handleChange = (e) => {
    const value = e.target.value;
    setQuery(value);
    setSelectedIndex(-1);
    debouncedFetch(value);
  };

  const handleKeyDown = (e) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex((prev) => Math.min(prev + 1, suggestions.length - 1));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex((prev) => Math.max(prev - 1, -1));
    } else if (e.key === 'Enter' && selectedIndex >= 0) {
      const selected = suggestions[selectedIndex];
      window.location.href = `/product/${selected.id}`;
    }
  };

  return (
    <div className="search-container">
      <input
        ref={inputRef}
        type="text"
        value={query}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
        placeholder="Rechercher un produit..."
        className="w-full p-2 border rounded"
      />
      {loading && <div className="loader">Chargement...</div>}
      {suggestions.length > 0 && (
        <ul className="suggestions-list absolute bg-white shadow-lg rounded mt-1 w-full z-10">
          {suggestions.map((item, idx) => (
            <li
              key={item.id}
              className={`p-2 hover:bg-gray-100 cursor-pointer ${idx === selectedIndex ? 'bg-gray-200' : ''}`}
              onClick={() => window.location.href = `/product/${item.id}`}
            >
              {item.name}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};
```

Les défis sont :
- Recalcul du filtrage à chaque changement de filtre (potentiel ralentissement)
- Saisie utilisateur rapide qui déclenche trop de re-renders

**Solution :**
1. Utiliser <code>useMemo</code> pour mémoriser les produits filtrés et ne recalculer que si <code>products</code>, <code>minPrice</code>, <code>maxPrice</code> ou <code>categories</code> changent.
2. Pour les champs de saisie continue (prix), utiliser <code>debounce</code> sur l'état local avant de mettre à jour l'état global des filtres.

```jsx
const filteredProducts = useMemo(() => {
  return products.filter(product => 
    product.price >= minPrice &&
    product.price <= maxPrice &&
    (selectedCategories.length === 0 || selectedCategories.includes(product.category))
  );
}, [products, minPrice, maxPrice, selectedCategories]);
```

```javascript
// hooks/useDebouncedState.js
import { useState, useCallback, useRef } from 'react';

export function useDebouncedState(initialValue, delay) {
  const [value, setValue] = useState(initialValue);
  const [debouncedValue, setDebouncedValue] = useState(initialValue);
  const timeoutRef = useRef(null);

  const updateValue = useCallback((newValue) => {
    setValue(newValue);
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    timeoutRef.current = setTimeout(() => {
      setDebouncedValue(newValue);
    }, delay);
  }, [delay]);

  return [value, debouncedValue, updateValue];
}

// Utilisation dans le composant
const PriceFilter = () => {
  const [localMin, debouncedMin, setLocalMin] = useDebouncedState(0, 300);

  useEffect(() => {
    // Le filtrage se déclenche uniquement sur debouncedMin
    applyFilter({ minPrice: debouncedMin });
  }, [debouncedMin]);

  return (
    <input
      type="range"
      value={localMin}
      onChange={(e) => setLocalMin(Number(e.target.value))}
    />
  );
};
```

Structure recommandée : un tableau d'objets avec <code>{ term, timestamp }</code> ou simplement un tableau de chaînes avec ordre implicite.

```javascript
const MAX_RECENT = 5;

function addToRecentSearches(term) {
  let recent = JSON.parse(localStorage.getItem('recent_searches') || '[]');
  // Supprimer l'entrée si elle existe déjà
  recent = recent.filter(t => t !== term);
  // Ajouter en tête
  recent.unshift(term);
  // Garder max 5 éléments
  if (recent.length > MAX_RECENT) recent.pop();
  localStorage.setItem('recent_searches', JSON.stringify(recent));
}
```

