```jsx
import { useState, useEffect } from 'react';

const SearchHistory = ({ onSearch }) => {
  const [recentSearches, setRecentSearches] = useState([]);
  const [trends, setTrends] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Charger l'historique local
    const stored = localStorage.getItem('recent_searches');
    if (stored) setRecentSearches(JSON.parse(stored));

    // Charger les tendances API
    fetch('/api/search/trends')
      .then(res => res.json())
      .then(data => {
        setTrends(data);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  const clearHistory = () => {
    localStorage.removeItem('recent_searches');
    setRecentSearches([]);
  };

  const handleTermClick = (term) => {
    onSearch(term);
  };

  return (
    <div className="search-history p-2 bg-gray-50 rounded">
      {recentSearches.length > 0 && (
        <div className="mb-3">
          <div className="flex justify-between items-center">
            <span className="text-sm font-semibold">Récentes :</span>
            <button onClick={clearHistory} className="text-xs text-red-500">Effacer</button>
          </div>
          <div className="flex flex-wrap gap-2 mt-1">
            {recentSearches.map((term, idx) => (
              <button
                key={idx}
                onClick={() => handleTermClick(term)}
                className="text-sm bg-white px-2 py-1 rounded shadow hover:bg-gray-100"
              >
                {term}
              </button>
            ))}
          </div>
        </div>
      )}

      <div>
        <span className="text-sm font-semibold">Tendances :</span>
        {loading ? (
          <div className="text-xs text-gray-400">Chargement...</div>
        ) : (
          <div className="flex flex-wrap gap-2 mt-1">
            {trends.map((term, idx) => (
              <button
                key={idx}
                onClick={() => handleTermClick(term)}
                className="text-sm bg-indigo-50 text-indigo-700 px-2 py-1 rounded hover:bg-indigo-100"
              >
                🔥 {term}
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};
```

```javascript
import { useQuery } from '@tanstack/react-query';

const searchProducts = async (query) => {
  if (!query || query.length < 2) return [];
  const response = await fetch(`/api/products/search?q=${encodeURIComponent(query)}`);
  if (!response.ok) throw new Error('Erreur recherche');
  return response.json();
};

export const useSearch = (query) => {
  return useQuery({
    queryKey: ['search', query],
    queryFn: () => searchProducts(query),
    enabled: query && query.length >= 2, // Ne s'exécute que si query valide
    staleTime: 5 * 60 * 1000, // 5 minutes de cache
    gcTime: 10 * 60 * 1000,
    placeholderData: (previousData) => previousData,
  });
};

// Utilisation dans le composant
const { data, isLoading, isError } = useSearch(debouncedQuery);
```

```javascript
import { useQueryClient } from '@tanstack/react-query';

const SearchPage = () => {
  const queryClient = useQueryClient();
  const [trends, setTrends] = useState([]);

  useEffect(() => {
    // 1. Récupérer les tendances
    fetch('/api/search/trends')
      .then(res => res.json())
      .then(trendsList => {
        setTrends(trendsList);
        // 2. Précharger les résultats pour chaque tendance
        trendsList.forEach(term => {
          queryClient.prefetchQuery({
            queryKey: ['search', term],
            queryFn: () => searchProducts(term),
            staleTime: 5 * 60 * 1000,
          });
        });
      });
  }, [queryClient]);

  // ...
};
```

Avantages :
- L'utilisateur voit les résultats instantanément en cliquant sur une tendance
- Réduction du temps de chargement perçu
- Meilleure expérience utilisateur mobile
